blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>budowę prostego zdania po angielsku</strong>: czym jest podmiot, czasownik i dopełnienie oraz jak układać je w poprawnej kolejności S–V–O.",
    "rules": [
        {
            "label": "Subject (S)",
            "color": "emerald",
            "text": "<strong>podmiot</strong> — kto lub co wykonuje czynność:",
            "example": "She / The cat / My friends"
        },
        {
            "label": "Verb (V)",
            "color": "blue",
            "text": "<strong>czasownik</strong> — czynność albo stan:",
            "example": "reads / is / have"
        },
        {
            "label": "Object (O)",
            "color": "amber",
            "text": "<strong>dopełnienie</strong> — na kogo lub na co skierowana jest czynność:",
            "example": "a book / music / a new car"
        }
    ]
}

{
    "title": "1. Co to jest zdanie proste?",
    "intro": "Zdanie proste (simple sentence) ma jeden podmiot i jedno orzeczenie:",
    "items": [
        {
            "label": "Jeden podmiot",
            "title": "Subject",
            "subtitle": "Jedna osoba albo rzecz wykonuje czynność"
        },
        {
            "label": "Jedno orzeczenie",
            "title": "Verb",
            "subtitle": "Jedna czynność albo jeden stan"
        },
        {
            "label": "Pełna myśl",
            "title": "Complete thought",
            "subtitle": "Zdanie ma pełny sens"
        }
    ]
}

{
    "title": "2. Subject — podmiot",
    "sections": [
        {
            "label": "Co to jest podmiot",
            "color": "emerald",
            "description": "<strong>Subject</strong> to wyraz albo grupa wyrazów, która mówi, kto lub co wykonuje czynność. W zwykłym zdaniu twierdzącym podmiot stoi na początku.",
            "examples": [
                {
                    "en": "I study English.",
                    "ua": "Uczę się angielskiego."
                },
                {
                    "en": "She works at a bank.",
                    "ua": "Pracuje w banku."
                },
                {
                    "en": "The children play outside.",
                    "ua": "Dzieci bawią się na dworze."
                }
            ]
        },
        {
            "label": "Rodzaje podmiotu",
            "color": "sky",
            "description": "Podmiotem może być <strong>zaimek</strong> (I, you, he, she, it, we, they), <strong>rzeczownik</strong> (Tom, dog, car) albo <strong>grupa wyrazów</strong> (my best friend, the old man).",
            "examples": [
                {
                    "en": "He is a doctor.",
                    "ua": "On jest lekarzem."
                },
                {
                    "en": "Maria speaks Spanish.",
                    "ua": "Maria mówi po hiszpańsku."
                },
                {
                    "en": "My older brother lives in Kyiv.",
                    "ua": "Mój starszy brat mieszka w Kijowie."
                }
            ]
        }
    ]
}

{
    "title": "3. Verb — czasownik",
    "sections": [
        {
            "label": "Co to jest czasownik",
            "color": "emerald",
            "description": "<strong>Verb</strong> wyraża czynność albo stan. W prostym zdaniu po angielsku stoi po podmiocie.",
            "examples": [
                {
                    "en": "She reads books.",
                    "ua": "Czyta książki."
                },
                {
                    "en": "He is happy.",
                    "ua": "Jest szczęśliwy."
                },
                {
                    "en": "They have a car.",
                    "ua": "Mają samochód."
                }
            ]
        },
        {
            "label": "Typy czasowników",
            "color": "sky",
            "description": "Najczęściej wyróżniamy <strong>action verbs</strong> (run, eat, write), <strong>linking verbs</strong> (be, seem, become) i <strong>auxiliary verbs</strong> (do, have, will).",
            "examples": [
                {
                    "en": "I eat breakfast at 8.",
                    "ua": "Jem śniadanie o ósmej."
                },
                {
                    "en": "She is a teacher.",
                    "ua": "Ona jest nauczycielką."
                },
                {
                    "en": "They do not like coffee.",
                    "ua": "Oni nie lubią kawy."
                }
            ]
        }
    ]
}

{
    "title": "4. Object — dopełnienie",
    "sections": [
        {
            "label": "Co to jest dopełnienie",
            "color": "emerald",
            "description": "<strong>Object</strong> to wyraz albo grupa wyrazów, na które skierowana jest czynność. Zwykle stoi po czasowniku.",
            "examples": [
                {
                    "en": "She reads a book.",
                    "ua": "Czyta książkę."
                },
                {
                    "en": "I love my family.",
                    "ua": "Kocham swoją rodzinę."
                },
                {
                    "en": "He bought a new car.",
                    "ua": "Kupił nowy samochód."
                }
            ]
        },
        {
            "label": "Dopełnienie bliższe i dalsze",
            "color": "sky",
            "description": "<strong>Direct object</strong> odpowiada na pytanie „co?”, a <strong>indirect object</strong> na pytanie „komu?”.",
            "examples": [
                {
                    "en": "She gave me a gift.",
                    "ua": "Dała mi prezent."
                },
                {
                    "en": "I sent him a letter.",
                    "ua": "Wysłałem mu list."
                }
            ],
            "note": "Typowy szyk: <strong>S + V + indirect object + direct object</strong> albo <strong>S + V + direct object + to/for + indirect object</strong>."
        }
    ]
}

{
    "title": "5. Pełny schemat S–V–O",
    "intro": "Podstawowy wzór prostego zdania twierdzącego wygląda tak:",
    "rows": [
        {
            "en": "Subject (S)",
            "ua": "podmiot",
            "note": "I, She, The dog, My friends"
        },
        {
            "en": "Verb (V)",
            "ua": "czasownik",
            "note": "read, is, have, like"
        },
        {
            "en": "Object (O)",
            "ua": "dopełnienie",
            "note": "books, music, a car"
        }
    ],
    "warning": "📌 W najprostszym modelu mamy: <strong>Subject + Verb + Object</strong>."
}

{
    "title": "6. Przykłady zdań w szyku S–V–O",
    "sections": [
        {
            "label": "Proste przykłady",
            "color": "emerald",
            "description": "To najprostsze zdania zbudowane według schematu <strong>Subject + Verb + Object</strong>.",
            "examples": [
                {
                    "en": "I eat breakfast.",
                    "ua": "Jem śniadanie."
                },
                {
                    "en": "She loves music.",
                    "ua": "Ona kocha muzykę."
                },
                {
                    "en": "They play football.",
                    "ua": "Oni grają w piłkę nożną."
                }
            ]
        },
        {
            "label": "Dłuższe przykłady",
            "color": "sky",
            "description": "Podmiotem albo dopełnieniem może być też dłuższa grupa wyrazów.",
            "examples": [
                {
                    "en": "My best friend speaks three languages.",
                    "ua": "Mój najlepszy przyjaciel mówi trzema językami."
                },
                {
                    "en": "The old man reads the morning newspaper.",
                    "ua": "Starszy pan czyta poranną gazetę."
                },
                {
                    "en": "Our teacher explains difficult grammar rules.",
                    "ua": "Nasz nauczyciel wyjaśnia trudne zasady gramatyki."
                }
            ]
        }
    ]
}

{
    "title": "7. Zdania bez dopełnienia (S–V)",
    "sections": [
        {
            "label": "Czasowniki nieprzechodnie",
            "color": "emerald",
            "description": "Niektóre czasowniki nie potrzebują dopełnienia. Wtedy zdanie ma prosty układ <strong>S + V</strong>.",
            "examples": [
                {
                    "en": "She sleeps.",
                    "ua": "Ona śpi."
                },
                {
                    "en": "The baby cries.",
                    "ua": "Dziecko płacze."
                },
                {
                    "en": "Birds fly.",
                    "ua": "Ptaki latają."
                }
            ]
        },
        {
            "label": "To be i complement",
            "color": "sky",
            "description": "Po <strong>to be</strong> bardzo często pojawia się nie dopełnienie, ale <strong>complement</strong>, czyli element opisujący podmiot.",
            "examples": [
                {
                    "en": "She is a doctor.",
                    "ua": "Ona jest lekarzem."
                },
                {
                    "en": "They are happy.",
                    "ua": "Oni są szczęśliwi."
                },
                {
                    "en": "I am at home.",
                    "ua": "Jestem w domu."
                }
            ]
        }
    ]
}

{
    "title": "8. Angielski a polski szyk zdania",
    "intro": "Najważniejsza różnica jest taka:",
    "rows": [
        {
            "en": "English: fixed word order",
            "ua": "angielski: stały szyk",
            "note": "She reads books. ✅"
        },
        {
            "en": "Polish: more flexible word order",
            "ua": "polski: bardziej swobodny szyk",
            "note": "Ona czyta książki. / Książki czyta ona. ✅"
        },
        {
            "en": "Wrong in English",
            "ua": "błędnie po angielsku",
            "note": "Books reads she. ❌"
        }
    ],
    "warning": "⚠️ W angielskim kolejność wyrazów mocno wpływa na znaczenie, więc nie można jej dowolnie przestawiać."
}

{
    "title": "9. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomijanie podmiotu.",
            "wrong": "Is raining. / Am tired.",
            "right": "✅ <span class=\"font-mono\">It is raining. / I am tired.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Niepoprawny szyk S–V–O.",
            "wrong": "Books reads she every day.",
            "right": "✅ <span class=\"font-mono\">She reads books every day.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Dopełnienie przed czasownikiem.",
            "wrong": "I English study.",
            "right": "✅ <span class=\"font-mono\">I study English.</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Podmiot po czasowniku w zwykłym zdaniu twierdzącym.",
            "wrong": "Plays Tom football.",
            "right": "✅ <span class=\"font-mono\">Tom plays football.</span>"
        }
    ]
}

{
    "title": "11. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Rozpoznaj element zdania",
    "select_intro": "Wskaż, jaką funkcję pełni wyróżnione słowo.",
    "selects": [
        {
            "label": "SHE reads books. (Subject / Verb / Object)",
            "prompt": "Jaki to element?"
        },
        {
            "label": "She READS books. (Subject / Verb / Object)",
            "prompt": "Jaki to element?"
        },
        {
            "label": "She reads BOOKS. (Subject / Verb / Object)",
            "prompt": "Jaki to element?"
        }
    ],
    "options": [
        "Subject",
        "Verb",
        "Object"
    ],
    "input_title": "Ćwiczenie 2. Ułóż zdanie w szyku S–V–O",
    "input_intro": "Ustaw wyrazy w poprawnej kolejności.",
    "inputs": [
        {
            "before": "(loves / music / Maria)",
            "after": "→"
        },
        {
            "before": "(plays / he / tennis)",
            "after": "→"
        },
        {
            "before": "(books / read / the students)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw szyk zdania",
    "rephrase_intro": "Znajdź i popraw błąd w kolejności wyrazów.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Coffee drinks she.",
            "example_target": "She drinks coffee."
        },
        {
            "original": "1. English I study every day.",
            "placeholder": "Popraw szyk"
        },
        {
            "original": "2. Football plays my brother.",
            "placeholder": "Popraw szyk"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Sentence Structure — budowa zdania (SVO)",
            "current": true
        },
        {
            "label": "Parts of Speech — części mowy",
            "current": false
        },
        {
            "label": "Basic Word Order — podstawowy szyk zdania",
            "current": false
        }
    ]
}
